import pg from 'pg';
import dotenv from 'dotenv';

// Load environment variables
dotenv.config();

const { Pool } = pg;

const connectionString = process.env.DATABASE_URL;

if (!connectionString) {
  console.error('CRITICAL: DATABASE_URL environment variable is not defined!');
  process.exit(1);
}

// Create pg connection pool
const pool = new Pool({
  connectionString,
  // Maximum number of clients in the pool
  max: 20,
  // Number of milliseconds a client must sit idle in the pool before being closed
  idleTimeoutMillis: 30000,
  // Number of milliseconds to wait before timing out when connecting a new client
  connectionTimeoutMillis: 5000,
});

// Log pool errors
pool.on('error', (err) => {
  console.error('Unexpected database pool error:', err);
});

export default pool;

/**
 * Encodes a product's pagination attributes into a base64 cursor string.
 * @param {object} product - The product database object.
 * @param {string|Date} product.created_at - The creation timestamp of the product.
 * @param {string} product.id - The UUID of the product.
 * @returns {string} The base64 encoded cursor.
 */
export function encodeCursor(product) {
  if (!product || !product.created_at || !product.id) {
    throw new Error('Cannot encode cursor: product must have created_at and id');
  }

  // Ensure created_at is converted to ISO string for standard serialization
  const createdAtStr = product.created_at instanceof Date 
    ? product.created_at.toISOString() 
    : new Date(product.created_at).toISOString();

  const cursorObj = {
    createdAt: createdAtStr,
    id: product.id,
  };

  return Buffer.from(JSON.stringify(cursorObj)).toString('base64');
}

/**
 * Decodes a base64 cursor string into its pagination attributes.
 * @param {string} cursorStr - The base64 encoded cursor string.
 * @returns {object|null} The decoded cursor object containing { createdAt, id }, or null if malformed.
 */
export function decodeCursor(cursorStr) {
  if (!cursorStr) {
    return null;
  }

  try {
    const jsonStr = Buffer.from(cursorStr, 'base64').toString('utf8');
    const cursorObj = JSON.parse(jsonStr);

    if (!cursorObj.createdAt || !cursorObj.id) {
      return null;
    }

    // Validate that id is a string and createdAt can be parsed as a valid date
    const dateVal = new Date(cursorObj.createdAt);
    if (isNaN(dateVal.getTime())) {
      return null;
    }

    return {
      createdAt: cursorObj.createdAt,
      id: cursorObj.id,
    };
  } catch (err) {
    // Return null to signify that the cursor is malformed
    return null;
  }
}

/**
 * Centralized Express Error Handler Middleware.
 * Prevents duplicate try/catch blocks in controllers and sanitizes error responses.
 */
export default function errorHandler(err, req, res, next) {
  // Log the error stack trace internally for debugging
  console.error(`[Error] ${err.stack || err.message || err}`);

  const statusCode = err.statusCode || 500;
  const message = err.message || 'Internal Server Error';

  // Format error response
  res.status(statusCode).json({
    success: false,
    message: statusCode === 500 && process.env.NODE_ENV === 'production' 
      ? 'An unexpected error occurred on the server' 
      : message,
  });
}

import pool from '../db/pool.js';
import { encodeCursor } from '../utils/cursor.js';

/**
 * Service to retrieve a paginated list of products from PostgreSQL.
 * Supports category filtering and cursor pagination (created_at DESC, id DESC).
 * 
 * @param {object} options
 * @param {string} [options.category] - Category to filter products by.
 * @param {number} options.limit - Number of products to return per page.
 * @param {object|null} options.cursor - Decoded cursor object containing { createdAt, id }.
 * @returns {Promise<object>} The paginated results containing data, count, hasMore, and nextCursor.
 */
export async function getProducts({ category, limit, cursor }) {
  // Query limit + 1 records to check if a next page exists (hasMore)
  const queryLimit = limit + 1;
  let queryText = '';
  let queryParams = [];

  if (category) {
    if (cursor) {
      // Category filter WITH cursor
      queryText = `
        SELECT id, name, category, price, created_at, updated_at
        FROM products
        WHERE category = $1
          AND (
            created_at < $2
            OR (
              created_at = $2
              AND id < $3
            )
          )
        ORDER BY created_at DESC, id DESC
        LIMIT $4;
      `;
      queryParams = [category, cursor.createdAt, cursor.id, queryLimit];
    } else {
      // Category filter WITHOUT cursor (First Page)
      queryText = `
        SELECT id, name, category, price, created_at, updated_at
        FROM products
        WHERE category = $1
        ORDER BY created_at DESC, id DESC
        LIMIT $2;
      `;
      queryParams = [category, queryLimit];
    }
  } else {
    if (cursor) {
      // Global list WITH cursor
      queryText = `
        SELECT id, name, category, price, created_at, updated_at
        FROM products
        WHERE (
          created_at < $1
          OR (
            created_at = $1
            AND id < $2
          )
        )
        ORDER BY created_at DESC, id DESC
        LIMIT $3;
      `;
      queryParams = [cursor.createdAt, cursor.id, queryLimit];
    } else {
      // Global list WITHOUT cursor (First Page)
      queryText = `
        SELECT id, name, category, price, created_at, updated_at
        FROM products
        ORDER BY created_at DESC, id DESC
        LIMIT $1;
      `;
      queryParams = [queryLimit];
    }
  }

  // Execute the query
  const { rows } = await pool.query(queryText, queryParams);

  // Check if there are more records beyond the current limit
  const hasMore = rows.length > limit;

  // Slice to the actual limit if hasMore is true
  const data = hasMore ? rows.slice(0, limit) : rows;

  // Determine the next cursor using the last element of the sliced data
  let nextCursor = null;
  if (hasMore && data.length > 0) {
    const lastProduct = data[data.length - 1];
    nextCursor = encodeCursor(lastProduct);
  }

  return {
    data,
    count: data.length,
    nextCursor,
    hasMore,
  };
}

/*
===========================================================================
CURSOR PAGINATION VS OFFSET PAGINATION JUSTIFICATION
===========================================================================

1. How it works:
   Instead of skipping N records using OFFSET (e.g., LIMIT 20 OFFSET 100000), cursor pagination
   defines a unique, stable boundary point in the sorted dataset using the last fetched row's 
   sort columns (created_at, id).

2. Why it prevents duplicates:
   - Imagine a user is on Page 1. While reading, a new product is inserted.
   - In OFFSET pagination, the new row shifts the entire dataset down by 1. When the user requests 
     Page 2 (OFFSET 20), the 20th item from Page 1 is pushed to the 21st position and is read again.
   - In CURSOR pagination, the query demands rows where:
        (created_at < $1 OR (created_at = $1 AND id < $2))
     Since the newly inserted product has a newer timestamp (created_at > $1), it is excluded 
     from the result set of the subsequent pages. The user never sees duplicates.

3. Why it prevents missing rows:
   - Imagine a user is on Page 1. While reading, a product on Page 1 is deleted.
   - In OFFSET pagination, the dataset shifts up by 1. When the user requests Page 2 (OFFSET 20), 
     the item at position 21 is now at position 20, and gets skipped entirely.
   - In CURSOR pagination, because the boundary ($1, $2) is fixed based on the values of the last 
     seen record, the deletion of previous rows does not affect the starting point of the next query.
     Thus, no items are skipped.

4. Performance (O(1) vs O(N)):
   - OFFSET pagination requires PostgreSQL to read, sort, and discard all N records before N + Limit.
     At OFFSET 100,000, it reads 100,000 records only to throw them away, resulting in slow query times.
   - CURSOR pagination uses the composite index to jump directly to the target record via an 
     index range scan (O(log N)), ignoring the rest of the database, keeping queries fast at scale.
*/

import * as productService from '../services/productService.js';
import { decodeCursor } from '../utils/cursor.js';

// Valid categories as specified in the assignment requirements
const VALID_CATEGORIES = new Set([
  'electronics',
  'fashion',
  'books',
  'sports',
  'toys',
  'home',
  'beauty',
  'automotive'
]);

/**
 * Reusable async middleware wrapper to catch errors and forward them to errorHandler.
 * Avoids duplicating try/catch blocks across controllers.
 */
const asyncHandler = (fn) => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

/**
 * Controller to handle fetching paginated products.
 * GET /api/products
 */
export const getProducts = asyncHandler(async (req, res, next) => {
  const { limit: limitQuery, cursor: cursorQuery, category } = req.query;

  // 1. Validate category if provided
  if (category && !VALID_CATEGORIES.has(category)) {
    return res.status(400).json({
      success: false,
      message: 'Invalid category'
    });
  }

  // 2. Parse and validate limit
  let limit = 20; // Default limit
  if (limitQuery !== undefined) {
    const parsedLimit = parseInt(limitQuery, 10);
    // Ensure limit is a positive integer and <= 100
    if (isNaN(parsedLimit) || parsedLimit <= 0 || parsedLimit > 100) {
      return res.status(400).json({
        success: false,
        message: 'Invalid limit'
      });
    }
    limit = parsedLimit;
  }

  // 3. Parse and validate cursor if provided
  let cursor = null;
  if (cursorQuery !== undefined) {
    // If cursor parameter is empty string or empty space
    if (!cursorQuery.trim()) {
      return res.status(400).json({
        success: false,
        message: 'Invalid cursor'
      });
    }

    cursor = decodeCursor(cursorQuery);
    if (!cursor) {
      return res.status(400).json({
        success: false,
        message: 'Invalid cursor'
      });
    }
  }

  // 4. Retrieve products from service
  const result = await productService.getProducts({ category, limit, cursor });

  // 5. Send successful response
  return res.status(200).json({
    success: true,
    count: result.count,
    nextCursor: result.nextCursor,
    hasMore: result.hasMore,
    data: result.data
  });
});

import { Router } from 'express';
import * as productController from '../controllers/productController.js';

const router = Router();

// GET /api/products
router.get('/', productController.getProducts);

export default router;

import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import productRoutes from './routes/productRoutes.js';
import errorHandler from './middleware/errorHandler.js';

// Load environment variables
dotenv.config();

const app = express();

// Standard middleware
app.use(cors());
app.use(express.json());

// Routes
app.use('/api/products', productRoutes);

// Base route for simple health check
app.get('/', (req, res) => {
  res.status(200).json({
    status: 'healthy',
    message: 'Product Catalog API is running'
  });
});

// Centralized error handler (must be registered after all other routes/middleware)
app.use(errorHandler);

export default app;

import app from './app.js';
import pool from './db/pool.js';

const PORT = process.env.PORT || 5000;

const server = app.listen(PORT, () => {
  console.log(`Server is running in ${process.env.NODE_ENV || 'development'} mode on port ${PORT}`);
});

// Handle graceful shutdown for production readiness
const handleGracefulShutdown = async (signal) => {
  console.log(`Received ${signal}. Starting graceful shutdown...`);

  // Stop receiving new connections
  server.close(async () => {
    console.log('HTTP server closed.');

    try {
      // Close database connection pool
      await pool.end();
      console.log('Database pool closed.');
      process.exit(0);
    } catch (err) {
      console.error('Error during pool shutdown:', err);
      process.exit(1);
    }
  });

  // Force close after 10 seconds if shutdown hangs
  setTimeout(() => {
    console.error('Could not close connections in time, forcefully shutting down');
    process.exit(1);
  }, 10000);
};

process.on('SIGTERM', () => handleGracefulShutdown('SIGTERM'));
process.on('SIGINT', () => handleGracefulShutdown('SIGINT'));

import { faker } from '@faker-js/faker';
import pool from '../src/db/pool.js';

const TOTAL_PRODUCTS = 200000;
const BATCH_SIZE = 5000;
const CATEGORIES = [
  'electronics',
  'fashion',
  'books',
  'sports',
  'toys',
  'home',
  'beauty',
  'automotive'
];

async function seed() {
  console.log('Starting product database seeding...');
  const startTime = Date.now();

  // Test connection first
  try {
    await pool.query('SELECT 1');
    console.log('Database connection successful.');
  } catch (err) {
    console.error('Failed to connect to database during seeding:', err.message);
    process.exit(1);
  }

  // Clear existing products
  console.log('Clearing existing product data...');
  await pool.query('TRUNCATE TABLE products CASCADE;');

  const totalBatches = Math.ceil(TOTAL_PRODUCTS / BATCH_SIZE);
  console.log(`Generating and inserting ${TOTAL_PRODUCTS} products in ${totalBatches} batches of ${BATCH_SIZE}...`);

  // To simulate realistic "newest first" ordering, we'll assign timestamps 
  // that decrease sequentially, ensuring older records are further in the past.
  const baseTime = Date.now();

  for (let batchIndex = 0; batchIndex < totalBatches; batchIndex++) {
    const batchStartTime = Date.now();
    const valuesPlaceholders = [];
    const queryParams = [];

    const currentBatchSize = Math.min(BATCH_SIZE, TOTAL_PRODUCTS - (batchIndex * BATCH_SIZE));

    for (let i = 0; i < currentBatchSize; i++) {
      const globalIndex = batchIndex * BATCH_SIZE + i;

      const id = faker.string.uuid();
      const name = faker.commerce.productName();
      const category = CATEGORIES[globalIndex % CATEGORIES.length]; // Even distribution of categories
      const price = parseFloat(faker.commerce.price({ min: 5, max: 1000, dec: 2 }));

      // Ensure monotonic created_at dates decreasing in the past. 
      // Subtracting 10 seconds for each product.
      const createdAt = new Date(baseTime - globalIndex * 10000);
      const updatedAt = new Date(createdAt.getTime() + Math.floor(Math.random() * 5000)); // slightly after created_at

      const paramOffset = i * 6;
      valuesPlaceholders.push(`($${paramOffset + 1}, $${paramOffset + 2}, $${paramOffset + 3}, $${paramOffset + 4}, $${paramOffset + 5}, $${paramOffset + 6})`);

      queryParams.push(id, name, category, price, createdAt, updatedAt);
    }

    const insertQuery = `
      INSERT INTO products (id, name, category, price, created_at, updated_at)
      VALUES ${valuesPlaceholders.join(',\n')};
    `;

    await pool.query(insertQuery, queryParams);

    const batchDuration = Date.now() - batchStartTime;
    const progressPercent = (((batchIndex + 1) / totalBatches) * 100).toFixed(0);
    console.log(`[Batch ${batchIndex + 1}/${totalBatches}] ${progressPercent}% complete in ${batchDuration}ms`);
  }

  const totalDuration = ((Date.now() - startTime) / 1000).toFixed(2);
  console.log(`\nSuccess! Seeded ${TOTAL_PRODUCTS} products in ${totalDuration} seconds.`);
}

seed()
  .then(() => {
    console.log('Seeding process finished.');
    process.exit(0);
  })
  .catch((err) => {
    console.error('Seeding process failed with error:', err);
    process.exit(1);
  });

import fs from 'fs';
import path from 'path';
import pg from 'pg';
import dotenv from 'dotenv';

dotenv.config();

const { Client } = pg;

async function setup() {
  const dbUrlStr = process.env.DATABASE_URL;
  if (!dbUrlStr) {
    console.error('DATABASE_URL is not defined in environment variables.');
    process.exit(1);
  }

  let dbUrl;
  try {
    dbUrl = new URL(dbUrlStr);
  } catch (err) {
    console.error('Invalid DATABASE_URL format:', err.message);
    process.exit(1);
  }

  const targetDbName = dbUrl.pathname.slice(1) || 'product_catalog';

  // 1. Connect to the default 'postgres' database to check/create the target database
  dbUrl.pathname = '/postgres';
  const systemDbUrl = dbUrl.toString();

  console.log(`Connecting to database system to verify database '${targetDbName}'...`);
  const client = new Client({ connectionString: systemDbUrl });

  try {
    await client.connect();

    const dbCheckResult = await client.query(
      'SELECT 1 FROM pg_database WHERE datname = $1',
      [targetDbName]
    );

    if (dbCheckResult.rowCount === 0) {
      console.log(`Database '${targetDbName}' does not exist. Creating...`);
      // CREATE DATABASE cannot run inside a transaction block, so we execute it directly
      await client.query(`CREATE DATABASE "${targetDbName}";`);
      console.log(`Database '${targetDbName}' created successfully.`);
    } else {
      console.log(`Database '${targetDbName}' already exists.`);
    }
  } catch (err) {
    console.error('Error during database check/creation:', err.message);
    console.error('Make sure PostgreSQL is running and credentials in .env are correct.');
    process.exit(1);
  } finally {
    await client.end();
  }

  // 2. Connect to the target database and execute schema.sql
  console.log(`Connecting to '${targetDbName}' to execute schema.sql...`);
  const targetClient = new Client({ connectionString: dbUrlStr });

  try {
    await targetClient.connect();

    const schemaPath = path.resolve('sql', 'schema.sql');
    if (!fs.existsSync(schemaPath)) {
      throw new Error(`Schema file not found at: ${schemaPath}`);
    }

    const schemaSql = fs.readFileSync(schemaPath, 'utf8');

    console.log('Applying schema migrations (creating tables and indexes)...');
    await targetClient.query(schemaSql);
    console.log('Schema migration applied successfully.');
  } catch (err) {
    console.error('Error executing schema.sql:', err.message);
    process.exit(1);
  } finally {
    await targetClient.end();
  }
}

setup();

import pg from 'pg';

const { Client } = pg;

const candidates = [
  'postgresql://postgres@localhost:5432/postgres', // postgres, no password
  'postgresql://postgres:postgres@localhost:5432/postgres', // postgres, postgres password
  'postgresql://themohiitt@localhost:5432/postgres', // current user, no password
  'postgresql://themohiitt:themohiitt@localhost:5432/postgres', // current user as password
  'postgresql://@localhost:5432/postgres', // default socket/localhost
  'postgresql:///postgres', // Unix domain socket peer auth
];

async function probe() {
  console.log('Probing PostgreSQL connection candidates...');
  for (const connStr of candidates) {
    console.log(`Trying: ${connStr}`);
    const client = new Client({ connectionString: connStr, connectionTimeoutMillis: 2000 });
    try {
      await client.connect();
      console.log(`\nSUCCESS! Working connection string: ${connStr}`);
      await client.end();
      return connStr;
    } catch (err) {
      console.log(`Failed: ${err.message}`);
    }
  }
  console.log('\nAll standard TCP / socket connection attempts failed.');
  return null;
}

probe().then((res) => {
  if (res) {
    process.exit(0);
  } else {
    process.exit(1);
  }
});

